 1→import { useEffect, useId, useRef, useState, type ReactNode } from 'react';
 2→import './quick_look.scss';
 3→
 4→export interface QuickLookProps {
 5→  title: string;
 6→  children: ReactNode;
 7→  onClose: () => void;
 8→}
 9→
10→const EXIT_ANIMATION_MS = 150;
11→
12→export function QuickLook({ title, children, onClose }: QuickLookProps) {
13→  const [exiting, setExiting] = useState(false);
14→  const onCloseRef = useRef(onClose);
15→  const titleId = useId();
16→
17→  onCloseRef.current = onClose;
18→
19→  function animateOut() {
20→    if (exiting) return;
21→    setExiting(true);
22→    setTimeout(() => {
23→      onCloseRef.current();
24→    }, EXIT_ANIMATION_MS);
25→  }
26→
27→  useEffect(() => {
28→    function handleKeyDown(e: KeyboardEvent) {
29→      if (e.key === 'Escape' || e.key === ' ') {
30→        e.preventDefault();
31→        e.stopPropagation();
32→        animateOut();
33→      }
34→    }
35→
36→    window.addEventListener('keydown', handleKeyDown, true);
37→    return () => window.removeEventListener('keydown', handleKeyDown, true);
38→  }, []);
39→
40→  function handleBackdropClick(e: React.MouseEvent) {
41→    if (e.target === e.currentTarget) {
42→      animateOut();
43→    }
44→  }
45→
46→  return (
47→    <div
48→      className={`quick-look__backdrop${exiting ? ' quick-look__backdrop--exiting' : ''}`}
49→      onClick={handleBackdropClick}
50→      role="presentation"
51→    >
52→      <div
53→        className={`quick-look__card${exiting ? ' quick-look__card--exiting' : ''}`}
54→        role="dialog"
55→        aria-modal="true"
56→        aria-labelledby={titleId}
57→      >
58→        <div className="quick-look__header">
59→          <h2 className="quick-look__title" id={titleId}>
60→            {title}
61→          </h2>
62→          <button
63→            type="button"
64→            className="quick-look__close"
65→            onClick={() => animateOut()}
66→            aria-label="Close preview"
67→          >
68→            <svg width="12" height="12" viewBox="0 0 12 12" fill="none">
69→              <path
70→                d="M2.5 2.5L9.5 9.5M9.5 2.5L2.5 9.5"
71→                stroke="currentColor"
72→                strokeWidth="1.5"
73→                strokeLinecap="round"
74→              />
75→            </svg>
76→          </button>
77→        </div>
78→        <div className="quick-look__body">{children}</div>
79→      </div>
80→    </div>
81→  );
82→}
