 44→function filterSections(sections: SectionData[], query: string): SectionData[] {
 45→  if (!query) return sections;
 46→  const lower = query.toLowerCase();
 47→  return sections
 48→    .map(section => ({
 49→      ...section,
 50→      items: section.items.filter(
 51→        item =>
 52→          item.title.toLowerCase().includes(lower) ||
 53→          item.subtitle?.toLowerCase().includes(lower),
 54→      ),
 55→    }))
 56→    .filter(section => section.items.length > 0);
 57→}
 58→
 59→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
 60→  if (!query) return colors;
 61→  const lower = query.toLowerCase();
 62→  return colors.filter(
 63→    c =>
 64→      c.title.toLowerCase().includes(lower) ||
 65→      c.subtitle?.toLowerCase().includes(lower),
 66→  );
 67→}
 68→
 69→function flattenItems(sections: SectionData[]): ListItemData[] {
 70→  return sections.flatMap(s => s.items);
 71→}
